  "osint-toolkit": {
    "README.md": "# OSINT Toolkit\n\nOpen-source intelligence gathering: domain recon, subdomain enumeration, WHOIS, SSL cert analysis.\n\n## Quick Start\n```bash\npython3 osint.py --target example.com\npython3 osint.py --email user@example.com\n```",
    "osint.py": "#!/usr/bin/env python3\n# OSINT Toolkit - target profiling, email enumeration, social footprint\nimport argparse, json, re, socket, ssl, time\n\nclass OSINTToolkit:\n    def __init__(self, timeout=10):\n        self.timeout = timeout\n        self.results = {}\n\n    def dns_lookup(self, domain):\n        print(f'[*] DNS lookup: {domain}')\n        records = {}\n        try:\n            records['A'] = socket.gethostbyname_ex(domain)[2]\n        except Exception as e:\n            records['error'] = str(e)\n        return records\n\n    def whois_lookup(self, domain):\n        print(f'[*] WHOIS lookup: {domain}')\n        try:\n            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\n            s.settimeout(self.timeout)\n            s.connect(('whois.iana.org', 43))\n            s.send(f'{domain}\\r\\n'.encode())\n            response = b''\n            while True:\n                data = s.recv(4096)\n                if not data: break\n                response += data\n            s.close()\n            return response.decode('utf-8', errors='ignore')[:2000]\n        except Exception as e:\n            return f'Error: {e}'\n\n    def get_ssl_cert(self, domain):\n        print(f'[*] SSL certificate: {domain}')\n        try:\n            ctx = ssl.create_default_context()\n            with ctx.wrap_socket(socket.socket(), server_hostname=domain) as s:\n                s.settimeout(self.timeout)\n                s.connect((domain, 443))\n                cert = s.getpeercert()\n                return {'subject': dict(x[0] for x in cert.get('subject', [])), 'issuer': dict(x[0] for x in cert.get('issuer', [])), 'notAfter': cert.get('notAfter')}\n        except Exception as e:\n            return {'error': str(e)}\n\n    def enumerate_subdomains(self, domain):\n        print(f'[*] Subdomain enumeration: {domain}')\n        subs = ['www', 'mail', 'ftp', 'admin', 'api', 'dev', 'staging', 'test', 'blog', 'shop', 'portal', 'vpn', 'cdn', 'app', 'dashboard', 'login', 'beta', 'mobile', 'support']\n        found = []\n        for sub in subs:\n            fqdn = f'{sub}.{domain}'\n            try:\n                socket.setdefaulttimeout(2)\n                ip = socket.gethostbyname(fqdn)\n                found.append({'subdomain': fqdn, 'ip': ip})\n                print(f'  Found: {fqdn} -> {ip}')\n            except socket.gaierror:\n                pass\n        return found\n\n    def scan_domain(self, domain):\n        self.results['domain'] = domain\n        self.results['dns'] = self.dns_lookup(domain)\n        self.results['whois'] = self.whois_lookup(domain)\n        self.results['ssl'] = self.get_ssl_cert(domain)\n        self.results['subdomains'] = self.enumerate_subdomains(domain)\n        return self.results\n\ndef main():\n    parser = argparse.ArgumentParser(description='OSINT Toolkit')\n    parser.add_argument('--target', help='Target domain')\n    parser.add_argument('--email', help='Target email address')\n    parser.add_argument('--output', help='Output JSON file')\n    args = parser.parse_args()\n    toolkit = OSINTToolkit()\n    if args.target:\n        results = toolkit.scan_domain(args.target)\n    elif args.email:\n        domain = args.email.split('@')[1] if '@' in args.email else args.email\n        results = {'email': args.email, 'domain_info': toolkit.scan_domain(domain)}\n    else:\n        parser.print_help()\n        return\n    if args.output:\n        with open(args.output, 'w') as f: json.dump(results, f, indent=2)\n        print(f'Results saved to {args.output}')\n    else:\n        print(json.dumps(results, indent=2))\n\nif __name__ == '__main__':\n    main()",
    "requirements.txt": "# No external dependencies (uses stdlib only)\n",
  },
