    "README.md": "# Linux Privilege Escalation Checker\n\nAutomated Linux privilege escalation checker. Identifies SUID binaries, sudo misconfigurations, writable paths, and cron jobs.\n\n## Quick Start\n```bash\npython3 privesc.py\n```",
    "privesc.py": "#!/usr/bin/env python3\n# Linux Privilege Escalation Checker - for authorized use only\nimport os, subprocess, sys, json\n\nclass PrivEscChecker:\n    def __init__(self):\n        self.findings = []\n        self.user = os.getenv('USER', 'unknown')\n        self.uid = os.getuid()\n\n    def run(self, cmd):\n        try:\n            return subprocess.check_output(cmd, shell=True, stderr=subprocess.DEVNULL, text=True).strip()\n        except Exception:\n            return ''\n\n    def check_suid(self):\n        print('[*] Checking SUID binaries...')\n        output = self.run('find / -perm -4000 -type f 2>/dev/null')\n        dangerous = ['/usr/bin/python', '/usr/bin/python3', '/usr/bin/perl', '/usr/bin/find', '/usr/bin/vim', '/usr/bin/nano', '/usr/bin/awk', '/usr/bin/nmap', '/usr/bin/bash', '/bin/sh']\n        for line in output.split('\\n'):\n            if line in dangerous:\n                self.findings.append({'type': 'SUID Binary', 'path': line, 'severity': 'HIGH', 'exploit': f'GTFOBins: https://gtfobins.github.io/gtfobins/{os.path.basename(line)}/' })\n                print(f'  [+] Dangerous SUID: {line}')\n\n    def check_sudo(self):\n        print('[*] Checking sudo permissions...')\n        output = self.run('sudo -l 2>/dev/null')\n        if 'NOPASSWD' in output:\n            self.findings.append({'type': 'Sudo NOPASSWD', 'output': output[:200], 'severity': 'CRITICAL'})\n            print('  [+] NOPASSWD sudo found!')\n        if '(ALL' in output:\n            self.findings.append({'type': 'Sudo ALL', 'output': output[:200], 'severity': 'CRITICAL'})\n\n    def check_writable_paths(self):\n        print('[*] Checking writable system paths...')\n        paths = ['/etc/passwd', '/etc/shadow', '/etc/sudoers', '/etc/cron.d', '/etc/cron.daily']\n        for path in paths:\n            if os.path.exists(path) and os.access(path, os.W_OK):\n                self.findings.append({'type': 'Writable Path', 'path': path, 'severity': 'CRITICAL'})\n                print(f'  [+] Writable: {path}')\n\n    def check_kernel(self):\n        print('[*] Checking kernel version...')\n        kernel = self.run('uname -r')\n        print(f'  Kernel: {kernel}')\n        self.findings.append({'type': 'Kernel Info', 'version': kernel, 'severity': 'INFO', 'note': 'Check https://www.exploit-db.com for kernel exploits'})\n\n    def run_all(self):\n        print(f'[*] Running as: {self.user} (UID: {self.uid})')\n        self.check_suid()\n        self.check_sudo()\n        self.check_writable_paths()\n        self.check_kernel()\n        print(f'\\n[*] Total findings: {len(self.findings)}')\n        for f in self.findings:\n            if f['severity'] in ('CRITICAL', 'HIGH'):\n                print(f\"  [{f['severity']}] {f['type']}: {f.get('path', f.get('output', '')[:80])}\")\n        return self.findings\n\ndef main():\n    checker = PrivEscChecker()\n    findings = checker.run_all()\n    with open('privesc_results.json', 'w') as f:\n        json.dump(findings, f, indent=2)\n    print('\\n[*] Results saved to privesc_results.json')\n\nif __name__ == '__main__':\n    main()",
    "requirements.txt": "# No external dependencies (uses stdlib only)\n",
