// ─── Payload Selector ────────────────────────────────────────────────────────
function selectPayload(title: string, category: string): string {
  const t = title.toLowerCase();
  const c = category.toLowerCase();

  if (t.includes("reverse shell") || t.includes("revshell")) return "reverse-shell";
  if (t.includes("vulnerability") || t.includes("vuln scanner") || t.includes("web scanner")) return "vuln-scanner";
  if (t.includes("credential") || t.includes("password spray") || t.includes("brute force")) return "vuln-scanner";
  if (t.includes("sql injection") || t.includes("sqli")) return "sql-injection";
  if (t.includes("xss") || t.includes("cross-site scripting")) return "xss-hunter";
  if (t.includes("wifi") || t.includes("wireless") || t.includes("wpa")) return "vuln-scanner";
  if (t.includes("privilege") || t.includes("privesc") || t.includes("escalation")) return "privesc-toolkit";
  if (t.includes("osint") || t.includes("reconnaissance") || t.includes("footprint")) return "osint-toolkit";
  if (t.includes("arbitrage") || t.includes("crypto bot") || t.includes("defi")) return "crypto-arbitrage";
  if (t.includes("seo") || t.includes("keyword") || t.includes("search engine")) return "seo-automation";
  if (t.includes("email campaign") || t.includes("bulk email") || t.includes("newsletter")) return "email-campaign";
  if (t.includes("chatbot") || t.includes("ai bot") || t.includes("llm") || t.includes("gpt")) return "ai-chatbot";
  if (t.includes("smart contract") || t.includes("solidity") || t.includes("blockchain audit")) return "smart-contract";
  if (t.includes("phishing") || t.includes("evilginx") || t.includes("credential capture")) return "vuln-scanner";
  if (t.includes("port scan") || t.includes("nmap") || t.includes("network scan")) return "vuln-scanner";
  if (t.includes("mitm") || t.includes("man in the middle") || t.includes("arp spoof")) return "vuln-scanner";
  if (t.includes("waf bypass") || t.includes("firewall bypass")) return "vuln-scanner";
  if (t.includes("payload") || t.includes("exploit")) return "reverse-shell";
  if (t.includes("keylogger") || t.includes("rat ") || t.includes("remote access")) return "reverse-shell";
  if (t.includes("affiliate") || t.includes("referral")) return "email-campaign";
  if (t.includes("ad ") || t.includes("advertising") || t.includes("campaign")) return "email-campaign";
  if (t.includes("token") || t.includes("nft") || t.includes("web3")) return "smart-contract";
  if (t.includes("grant") || t.includes("funding")) return "generic-py";
  if (t.includes("storage") || t.includes("file manager") || t.includes("s3")) return "generic-ts";
  if (t.includes("api") || t.includes("rest") || t.includes("graphql")) return "generic-ts";
  if (t.includes("docker") || t.includes("container") || t.includes("kubernetes")) return "generic-ts";
  if (t.includes("ci/cd") || t.includes("pipeline") || t.includes("github action")) return "generic-ts";
  if (t.includes("compliance") || t.includes("audit trail") || t.includes("gdpr")) return "generic-ts";
  if (t.includes("cloud") || t.includes("aws") || t.includes("azure") || t.includes("gcp")) return "generic-ts";
  if (t.includes("iac") || t.includes("terraform") || t.includes("infrastructure")) return "generic-ts";
  if (t.includes("code review") || t.includes("static analysis") || t.includes("linter")) return "generic-ts";
  if (t.includes("kill switch") || t.includes("emergency stop") || t.includes("circuit breaker")) return "generic-ts";
  if (t.includes("malware") || t.includes("antivirus") || t.includes("defense")) return "vuln-scanner";
  if (t.includes("secure file") || t.includes("encryption") || t.includes("pgp")) return "generic-py";
  if (t.includes("bug bounty") || t.includes("responsible disclosure")) return "vuln-scanner";

  // Category fallbacks
  if (c.includes("security") || c.includes("pentest") || c.includes("offensive")) return "vuln-scanner";
  if (c.includes("crypto") || c.includes("defi") || c.includes("web3")) return "crypto-arbitrage";
  if (c.includes("ai") || c.includes("ml") || c.includes("bot")) return "ai-chatbot";
  if (c.includes("web") || c.includes("saas") || c.includes("template")) return "generic-ts";
  if (c.includes("marketing") || c.includes("email") || c.includes("seo")) return "email-campaign";

  // Final fallback
  if (t.includes("typescript") || t.includes("node") || t.includes("react") || t.includes("next")) return "generic-ts";
  return "generic-py";
}

// ─── Zip Generator ──────────────────────────────────────────────────────────

async function generateZip(title: string, category: string): Promise<Buffer> {
  const key = selectPayload(title, category);
  const files = PAYLOADS[key] || PAYLOADS["generic-py"];

  const zip = new JSZip();
  for (const [filename, content] of Object.entries(files)) {
    zip.file(filename, content);
  }
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return (zip as any).generateAsync({ type: "nodebuffer", compression: "DEFLATE" }) as Promise<Buffer>;
}

// ─── Main Export ─────────────────────────────────────────────────────────────

export async function generateAndUploadPayloads(): Promise<{ updated: number; skipped: number; errors: number }> {
  const db = await getDb();
  if (!db) throw new Error("Database not initialized");

  const listings = await db.select().from(marketplaceListings);
  let updated = 0, skipped = 0, errors = 0;

  for (const listing of listings) {
    if (listing.fileUrl) {
      skipped++;
      continue;
    }
    try {
      const zipBuffer = await generateZip(listing.title, listing.category || "general");
      const storageKey = `marketplace/${listing.uid}/payload.zip`;
      const { url } = await storagePut(storageKey, zipBuffer, "application/zip");
      await db.update(marketplaceListings)
        .set({ fileUrl: url, fileSize: zipBuffer.length, fileType: "application/zip" })
        .where(eq(marketplaceListings.id, listing.id));
      console.log(`[marketplace-payload] Generated zip for "${listing.title}" (${Math.round(zipBuffer.length / 1024)}KB)`);
      updated++;
    } catch (err) {
      console.error(`[marketplace-payload] Error for "${listing.title}": ${err}`);
      errors++;
    }
  }

  console.log(`[marketplace-payload] Done: ${updated} updated, ${skipped} skipped, ${errors} errors`);
  return { updated, skipped, errors };
}
